2476	void Testbed::update_density_grid_nerf(
2477		float decay, uint32_t n_uniform_density_grid_samples, uint32_t n_nonuniform_density_grid_samples, cudaStream_t stream
2478	) {
2479		const uint32_t n_elements = NERF_GRID_N_CELLS() * (m_nerf.max_cascade + 1);
2480	
2481		m_nerf.density_grid.resize(n_elements);
2482	
2483		const uint32_t n_density_grid_samples = n_uniform_density_grid_samples + n_nonuniform_density_grid_samples;
2484	
2485		const uint32_t padded_output_width = m_nerf_network->padded_density_output_width();
2486	
2487		GPUMemoryArena::Allocation alloc;
2488		auto scratch = allocate_workspace_and_distribute<
2489			NerfPosition,       // positions at which the NN will be queried for density evaluation
2490			uint32_t,           // indices of corresponding density grid cells
2491			float,              // the resulting densities `density_grid_tmp` to be merged with the running estimate of the grid
2492			network_precision_t // output of the MLP before being converted to densities.
2493			>(stream, &alloc, n_density_grid_samples, n_elements, n_elements, n_density_grid_samples * padded_output_width);
2494	
2495		NerfPosition* density_grid_positions = std::get<0>(scratch);
2496		uint32_t* density_grid_indices = std::get<1>(scratch);
2497		float* density_grid_tmp = std::get<2>(scratch);
2498		network_precision_t* mlp_out = std::get<3>(scratch);
2499	
2500		if (m_training_step == 0 || m_nerf.training.n_images_for_training != m_nerf.training.n_images_for_training_prev) {
2501			m_nerf.training.n_images_for_training_prev = m_nerf.training.n_images_for_training;
2502			if (m_training_step == 0) {
2503				m_nerf.density_grid_ema_step = 0;
2504			}
2505			// Only cull away empty regions where no camera is looking when the cameras are actually meaningful.
2506			if (!m_nerf.training.dataset.has_rays) {
2507				linear_kernel(
2508					mark_untrained_density_grid,
2509					0,
2510					stream,
